[{'flowquest_monitor': '\'ECONNREFUSED\') { echo "Instance $url is DOWN", \'n\'; return false; }\n        echo "Instance $url is UP", \'n\'; return true;', 'notify_admin': "($down_instances as $instance) { $message .='Instance $instance is DOWN'; }\n        // Tutaj można dodać wysyłanie powiadomienia email lub SMS}", 'get_instance_urls': 'instance, url FROM demo_instances";\n        $result = $mysqli->query($query);\n        $instances = [];\n        while ($row = $result->fetch_assoc()) {\n            $instances[$row[\'instance\']] = $row[\'url\'];\n        }\n        return $instances;'}, {'$down_instances': '[];\n        foreach ($instances as $name => $url) {\n            if (!check_instance($url)) {\n                $down_instances[] = $name;\n            }\n        }\n        \n        if (count($down_instances) > 0) {\n            notify_admin($down_instances);\n        }\n        \n        echo "Monitoring completed. Down instances: " . count($down_instances), \'n\';\n        exit;'}]